                    </svg>
                )}
            </div>
            {typeof reactionCount === 'number' && reactionCount > 0 && (
                <span className="reaction-count">{reactionCount}</span>
            )}
            <ReactionPicker
                isOpen={showPicker}
                onSelect={handlePickerSelect}
                currentReaction={userReaction}
            />
        </div>
    );
};

export default ReactionButton;

