 79→    };
 80→
 81→    const handleOpenDeleteModal = (event, item) => {
 82→        event.stopPropagation();
 83→        setDeleteCandidate(item);
 84→        setActiveMenuId(null);
 85→    };
 86→
 87→    const handleCloseDeleteModal = () => {
 88→        setDeleteCandidate(null);
 89→    };
 90→
 91→    const handleConfirmDelete = () => {
 92→        if (!deleteCandidate || deleteMediaMutation.isPending) {
 93→            return;
 94→        }
 95→
 96→        deleteMediaMutation.mutate(deleteCandidate);
 97→    };
 98→
 99→    const handleCloseMedia = () => {
100→        setSelectedMedia(null);
101→    };
