 19→    const { ref: inViewRef, inView } = useInView({ threshold: 0.1 });
 20→
 21→    const { data, isLoading, isError, fetchNextPage, hasNextPage, isFetchingNextPage } = useInfiniteQuery({
 22→        queryKey: ["visitedProfileMedia", visitedUserId],
 23→        queryFn: ({ pageParam }) =>
 24→            getVisitedProfileMedia(session?.access_token, visitedUserId, pageParam, PROFILE_MEDIA_PAGE_SIZE),
 25→        initialPageParam: null,
 26→        getNextPageParam: (lastPage) => (lastPage?.hasMore ? lastPage?.nextCursor : undefined),
 27→        enabled: Boolean(visitedUserId && session?.access_token),
 28→        refetchOnWindowFocus: false,
 29→        staleTime: 1000 * 60 * 10,
 30→    });
 31→
 32→    const pages = data?.pages ?? [];
 33→    const mediaItems = pages.flatMap((page) => page?.data ?? []);
 34→    const unavailableBuckets = [...new Set(pages.flatMap((page) => page?.unavailableBuckets ?? []))];
 35→    const hasMedia = mediaItems.length > 0;
 36→
 37→    useEffect(() => {
 38→        if (inView && hasNextPage && !isFetchingNextPage) {
 39→            fetchNextPage();
 40→        }
 41→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 42→
 43→    useEffect(() => {
 44→        if (!selectedMedia) return;
 45→
 46→        const handleEscape = (event) => {
 47→            if (event.key === "Escape") {
 48→                setSelectedMedia(null);
 49→            }
 50→        };
 51→
 52→        window.addEventListener("keydown", handleEscape);
 53→        return () => window.removeEventListener("keydown", handleEscape);
 54→    }, [selectedMedia]);
 55→
 56→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
 57→
 58→    return (
 59→        <section className="profile-media-section" aria-label="Visited profile media">
 60→            <div className="profile-media-header-row">
 61→                <h2 className="profile-media-heading">
 62→                    Posts <span className="profile-media-count">({mediaItems.length})</span>
 63→                </h2>
 64→            </div>
 65→
 66→            {unavailableBuckets.length > 0 && <p className="profile-media-warning">Unable to list: {unavailableBuckets.join(", ")}.</p>}
 67→
 68→            {isLoading && (
 69→                <div className="profile-media-grid">
 70→                    {Array.from({ length: 9 }).map((_, index) => (
 71→                        <div key={`visited-media-loading-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
 72→                    ))}
 73→                </div>
 74→            )}
 75→
 76→            {!isLoading && isError && <p className="profile-media-empty-state">Unable to load media right now.</p>}
 77→
 78→            {!isLoading && !isError && !hasMedia && <p className="profile-media-empty-state">No media found yet.</p>}
 79→
 80→            {!isLoading && !isError && hasMedia && (
 81→                <div className="profile-media-grid">
 82→                    {mediaItems.map((item) => (
 83→                        <div key={item.id} className="profile-media-grid-item">
 84→                            <button
 85→                                className="profile-media-grid-image-button"
 86→                                type="button"
 87→                                onClick={() => setSelectedMedia(item)}
 88→                                title={`View ${item.bucket} image full size`}
 89→                            >
 90→                                <img className="profile-media-image" src={item.url} alt={`${item.bucket} media`} loading="lazy" />
 91→                            </button>
 92→                        </div>
 93→                    ))}
 94→                    {isFetchingNextPage &&
 95→                        Array.from({ length: PROFILE_MEDIA_PAGE_SIZE }).map((_, index) => (
 96→                            <div key={`visited-media-loading-next-${index}`} className="profile-media-grid-item profile-media-grid-loading-item" />
 97→                        ))}
 98→                </div>
 99→            )}
100→
101→            {!isLoading && hasMedia && hasNextPage && <div ref={inViewRef} className="profile-media-infinite-sentinel" />}
102→
103→            {selectedMedia &&
104→                profileParentContainer &&
105→                createPortal(
106→                    <div className="profile-media-lightbox-overlay" onClick={() => setSelectedMedia(null)} role="presentation">
107→                        <div
108→                            className="profile-media-lightbox-dialog"
109→                            role="dialog"
110→                            aria-modal="true"
111→                            aria-label="Full size media preview"
112→                            onClick={(event) => event.stopPropagation()}
113→                        >
114→                            <button
115→                                className="profile-media-lightbox-close"
116→                                type="button"
117→                                onClick={() => setSelectedMedia(null)}
118→                                aria-label="Close image preview"
119→                            >
120→                                <svg xmlns="http://www.w3.org/2000/svg" height="22" viewBox="0 -960 960 960" width="22" fill="currentColor">
121→                                    <path d="m291-240-51-51 189-189-189-189 51-51 189 189 189-189 51 51-189 189 189 189-51 51-189-189-189 189Z" />
122→                                </svg>
123→                            </button>
124→                            <img className="profile-media-lightbox-image" src={selectedMedia.url} alt={`${selectedMedia.bucket} media full size`} />
125→                        </div>
126→                    </div>,
127→                    profileParentContainer
128→                )}
129→        </section>
130→    );
131→};
132→
133→export default VisitedProfileMediaSection;
