  9→function extractExcerpt(content, maxLen = 120) {
 10→    if (!content) return '';
 11→    try {
 12→        const root = typeof content === 'string' ? JSON.parse(content) : content;
 13→        const texts = [];
 14→        const walk = (node) => {
 15→            if (node.text) texts.push(node.text);
 16→            if (node.children) node.children.forEach(walk);
 17→        };
 18→        walk(root.root || root);
 19→        const full = texts.join(' ').replace(/\s+/g, ' ').trim();
 20→        if (full.length <= maxLen) return full;
 21→        return full.slice(0, maxLen).replace(/\s+\S*$/, '') + '…';
 22→    } catch {
 23→        return '';
 24→    }
 25→}
