 33→function RelatedPostCard({ post, index }) {
 34→    const navigate = useNavigate();
 35→
 36→    const handleClick = () => {
 37→        navigate(`/home/post/${post.id}`);
 38→    };
 39→
 40→    const title = post.title || 'Untitled';
 41→    const excerpt = extractExcerpt(post.content);
 42→
 43→    // Map similarity to accent opacity (higher = brighter accent line)
 44→    const accentOpacity = Math.min(1, Math.max(0.3, (post.semantic_similarity - 0.25) / 0.5));
 45→
 46→    return (
 47→        <motion.div
 48→            className="rp-card"
 49→            onClick={handleClick}
 50→            initial={{ opacity: 0, y: 12 }}
 51→            animate={{ opacity: 1, y: 0 }}
 52→            transition={{
 53→                duration: 0.35,
 54→                delay: index * 0.06,
 55→                ease: [0.25, 0.46, 0.45, 0.94],
 56→            }}
 57→        >
 58→            <div
 59→                className="rp-card-accent"
 60→                style={{ opacity: accentOpacity }}
 61→            />
 62→            <div className="rp-card-content">
 63→                <h4 className="rp-card-title">{title}</h4>
 64→                {excerpt && <p className="rp-card-excerpt">{excerpt}</p>}
 65→                <div className="rp-card-meta">
 66→                    <div className="rp-card-author">
 67→                        {post.user_image_url ? (
 68→                            <img
 69→                                src={post.user_image_url}
 70→                                alt=""
 71→                                className="rp-card-avatar"
 72→                            />
 73→                        ) : (
 74→                            <div className="rp-card-avatar rp-card-avatar-placeholder" />
 75→                        )}
 76→                        <span className="rp-card-name">
 77→                            {post.user_name || 'Anonymous'}
 78→                        </span>
 79→                        {post.user_badge && (
 80→                            <VerifiedBadge badge={post.user_badge} size={12} />
 81→                        )}
 82→                    </div>
 83→                    <span className="rp-card-date">
 84→                        {formatPostDate(post.created_at)}
 85→                    </span>
 86→                </div>
 87→            </div>
 88→        </motion.div>
 89→    );
 90→}
