112→export default function RelatedPosts({ journalId }) {
113→    const { data, isLoading } = useQuery({
114→        queryKey: ['relatedPosts', journalId],
115→        queryFn: () => getRelatedPosts(journalId),
116→        enabled: !!journalId,
117→        staleTime: 10 * 60 * 1000,
118→        retry: false,
119→    });
120→
121→    if (isLoading) {
122→        return (
123→            <section className="rp-section">
124→                <RelatedPostsSkeleton />
125→            </section>
126→        );
127→    }
128→
129→    // Don't render anything if no confidence or no posts
130→    if (!data || data.confidence === 'none' || !data.posts?.length) {
131→        return null;
132→    }
133→
134→    const label = CONFIDENCE_LABELS[data.confidence];
135→    if (!label) return null;
136→
137→    return (
138→        <section className="rp-section">
139→            <h3 className="rp-heading">
140→                <svg className="rp-heading-icon" viewBox="0 0 16 16" fill="none">
141→                    <path d="M8 1l1.796 4.236L14.5 6.18l-3.25 3.382.588 4.938L8 12.236 4.162 14.5l.588-4.938L1.5 6.18l4.704-.944z"
