143→                    <path d="M8 4.5l.898 2.118L11.25 7.09l-1.625 1.691.294 2.469L8 10.118 5.581 11.25l.294-2.469L4.25 7.09l2.352-.472z"
144→                          fill="currentColor" opacity="0.3" />
145→                </svg>
146→                {label}
147→            </h3>
148→            <div className="rp-grid">
149→                {data.posts.map((post, index) => (
150→                    <RelatedPostCard
